var area = null;
var markers = null;
var area_bounds = new google.maps.LatLngBounds();

function PlanarPolygonAreaMeters(points) {
    var earthRadiusMeters   = 6367460.0;
    var metersPerDegree     = 2.0*Math.PI*earthRadiusMeters/360.0;
    var radiansPerDegree    = Math.PI/180.0;
    var a = 0.0;
    for(var i = 0;i<points.length;++i) {
        var j = (i+1)%points.length;
        var xi  = points[i].lng*metersPerDegree*Math.cos(points[i].lat*radiansPerDegree);
        var yi  = points[i].lat*metersPerDegree;
        var xj  = points[j].lng*metersPerDegree*Math.cos(points[j].lat*radiansPerDegree);
        var yj  = points[j].lat*metersPerDegree;
        a += xi*yj-xj*yi;
    }
    return Math.abs(a/2.0);
}
function calc_area (area) {
    var point = [];
    $.each(area, function(index, val) {
        point.push({'lat':val[0],'lng':val[1]});
    });
    area_hectare = PlanarPolygonAreaMeters(point);
    area_hectare = area_hectare/10000;
    return area_hectare;
}
function show_polygon (area) {
    $.each(area, function(index, val) {
        var myLatLng = new google.maps.LatLng(val[0],val[1]);
        area_bounds.extend(myLatLng);
    });

    $('#map_garden_area').gmap3("get")
        .fitBounds(area_bounds);

    $("#map_garden_area").gmap3({
        polygon: {
            tag: 'Area',
            options: {
                strokeColor: "yellow",
                strokeOpacity: 0.8,
                strokeWeight: 2,
                fillColor: "yellow",
                fillOpacity: 0.35,
                paths: area
            },
        }
    })
}

function hide_polygon () {
    $("#map_garden_area").gmap3({
        clear: {
            name: "polyline"
        }
    }).gmap3({
        clear: {
            name: "polygon"
        }
    }).gmap3({
        clear: {
            tag: "polygon_marker"
        }
    });
}

function edit_polygon () {
    Ext.getCmp('btnPolygonEdit').hide();
    Ext.getCmp('btnPolygonSave').show();
    Ext.getCmp('btnPolygonCancel').show();
    hide_polygon();
    markers = [];
    $.each(area, function(index, val) {
        addMarker(val[0], val[1]);
    });
}

function download_polygon_kml () {
    var FarmerID = Ext.getCmp('polygonFarmerID').getValue();
    var GardenNr = Ext.getCmp('polygonGardenNr').getValue();
    var SurveyNr = Ext.getCmp('polygonSurveyNr').getValue();
    window.open(m_api+'/farmer/print_kml?farmerid=' + FarmerID + '&gardennr=' + GardenNr + '&surveynr=' + SurveyNr);
}

function save_polygon () {
    area = [];
    $.each(markers, function(index, val) {
        area.push([val.lat, val.lng]);
    });
    area_hectare = calc_area(area);
    var FarmerID = Ext.getCmp('polygonFarmerID').getValue();
    var GardenNr = Ext.getCmp('polygonGardenNr').getValue();
    var SurveyNr = Ext.getCmp('polygonSurveyNr').getValue();
    send_polygon(FarmerID,GardenNr,SurveyNr,area,area_hectare);
}

function send_polygon (FarmerID,GardenNr,SurveyNr,area,area_hectare) {
    $.ajax({
        url: m_polygon,
        type: 'POST',
        data: {
            FarmerID: FarmerID,
            GardenNr: GardenNr,
            SurveyNr: SurveyNr,
            area: area,
            area_hectare: area_hectare
        },
    })
    .done(function() {
        console.log("success");
        Ext.MessageBox.alert('Success',lang('Polygon saved'));
    })
    .fail(function() {
        console.log("error");
        Ext.MessageBox.alert('Failure',lang('Failed to save polygon'));
    })
    .always(function() {
        draw_map(FarmerID,GardenNr,SurveyNr);
    });

}

function addMarker(lat, lng)
{
    var mark = [];
    var id = markers.length;
    if (!lat || !lng) {
        var map = $('#map_garden_area').gmap3('get');
        var lat = map.getCenter().lat();
        var lng = map.getCenter().lng();
    }
    mark["lat"] = lat;
    mark["lng"] = lng;

    markers[id] = mark;

    $("#map_garden_area").gmap3({
        marker: {
            latLng: [lat, lng],
            id: id+1,
            tag: 'polygon_marker',
            options: {
                draggable: true
            },
            events: {
                dragend: function(marker, event, data) {
                    markers[data.id-1]["lat"] = marker.getPosition().lat();
                    markers[data.id-1]["lng"] = marker.getPosition().lng();
                    makePoly();

                    Ext.getCmp('GardenHaUnPolygon').setValue(number_format(calc_area(area),2,'.',','));
                },
                // click: function(marker, event, data) {
                //     var button = $('#delete-marker');
                //     button.text('Delete Marker ' + data.id);
                //     button.data('id', data.id);
                //     button.show();
                // }
            }
        }
    });
    makePoly();
}

function makePoly()
{
    var map = $('#map_garden_area').gmap3('get');
    var tmp_marker = [];
    // $('#markers-text').html('');

    //var bounds = new google.maps.LatLngBounds();
    $.each(markers, function(i){
        if (markers[i]) {
            tmp_marker.push([markers[i].lat, markers[i].lng]);
            //$('#markers-text').append('['+markers[i].lat + ',' + markers[i].lng + '],<br/>');
//            latLng = new google.maps.LatLng(parseFloat(markers[i].lat), parseFloat(markers[i].lng));
//            bounds.extend(latLng);
        }
    });
    // $('#polygon').val('[['+tmp_marker.join('],[')+']]');
    Ext.getCmp('polygon').setValue('[['+tmp_marker.join('],[')+']]');
    $("#map_garden_area").gmap3({
        clear: {
            name: "polyline"
        }
    }).gmap3({
        clear: {
            name: "polygon"
        }
    });
    if (tmp_marker.length == 2) {
        // console.log('polyline');
        $("#map_garden_area").gmap3({
            polyline: {
                options: {
                    strokeColor: "#FF0000",
                    strokeOpacity: 1.0,
                    strokeWeight: 2,
                    path: tmp_marker
                }
            }
        });
        //map.fitBounds(bounds);
    } else if (tmp_marker.length > 2) {
        // console.log('polygon');
        tmp_marker.push(tmp_marker[0]);
        $("#map_garden_area").gmap3({
            polygon: {
                options: {
                    strokeColor: "#FF0000",
                    strokeOpacity: 0.8,
                    strokeWeight: 2,
                    fillColor: "#FF0000",
                    fillOpacity: 0.35,
                    paths: tmp_marker
                },
                events: {
                    click: function(polygon, event, data) {
                        var vertices = polygon.getPath();

                        var points = [];
                        for (var i = 0; i < vertices.length; i++) {
                            var xy = vertices.getAt(i);
                            points.push({'lat':xy.lat(),'lng':xy.lng()});
                        }
                        var area = PlanarPolygonAreaMeters(points);
                        area = area/10000;

                        contentString = area.toFixed(2) + ' ha';

                        infowindow  = $(this).gmap3({get:{name:"infowindow"}});
                        if (infowindow){
                            infowindow.open(map, polygon);
                            infowindow.setContent(contentString);
                            infowindow.setPosition(event.latLng);
                        } else {
                            $(this).gmap3({
                                infowindow:{
                                    anchor:polygon,
                                    options:{
                                        content: contentString,
                                        position: event.latLng
                                    }
                                }
                            });
                        }
                    }
                }
            }
        });
        //map.fitBounds(bounds);
    }
}
function draw_map(FarmerID, GardenNr, SurveyNr) {
    $('#map_garden_area').gmap3({
        map: {
            options: {
                center: [-2.0836809794977484, 113.63967449468988],
                zoom: 5,
                //mapTypeControl: false,
                panControl: true,
                zoomControl: true,
                //scaleControl: false,
                streetViewControl: false,
                rotateControl: false,
                rotateControlOptions: false,
                overviewMapControl: false,
                OverviewMapControlOptions: false,
                scrollwheel: true,
                mapTypeId: google.maps.MapTypeId.HYBRID
            }
        }
    });
    $('#map_garden_area').gmap3({clear: {}});
    area_bounds = new google.maps.LatLngBounds();

    $.get(m_polygon+'?farmer='+FarmerID+'&garden='+GardenNr+'&survey='+SurveyNr, function(data) {
        if (data) {
            if (data.garden.Latitude !== '' && data.garden.Longitude !== '') {
                var icon_path = m_base_url + 'img/maps/';
                $("#map_garden_area").gmap3({
                    marker:{
                        values:[
                            {
                                latLng:[parseFloat(data.garden.Latitude),parseFloat(data.garden.Longitude)],
                                tag:'garden',
                                options: {
                                    icon: icon_path + "farmer.png"
                                },
                            }
                        ]
                    }
                });

                var myLatLng = new google.maps.LatLng(parseFloat(data.garden.Latitude),parseFloat(data.garden.Longitude));
                area_bounds.extend(myLatLng);
                $('#map_garden_area').gmap3("get")
                    .fitBounds(area_bounds);
            }
            Ext.getCmp('polygonFarmerID').setValue(FarmerID);
            Ext.getCmp('polygonGardenNr').setValue(GardenNr);
            Ext.getCmp('polygonSurveyNr').setValue(SurveyNr);
            area = data.area;
            // show_polygon(data.area);
            show_polygon(area);
            // var area = calc_area(data.area);
            Ext.getCmp('GardenHaUnPolygon').setValue(number_format(calc_area(area),2,'.',','));
            Ext.getCmp('MapSource').setValue(data.survey.SurveyNr+' - '+data.survey.SurveyTxt);
            Ext.getCmp('btnPolygonEdit').show();
        };
    });
}

