    function isNumber(n) {
        return !isNaN(parseFloat(n)) && isFinite(n);
    }

    function PohonTotal() {
        Ext.getCmp('PohonTotal').setValue((parseInt(Ext.getCmp('PohonTBM').getValue()) || 0) + (parseInt(Ext.getCmp('PohonTM').getValue()) || 0) + (parseInt(Ext.getCmp('PohonRehab').getValue()) || 0))
        TotalTrees()

        var totalNya = parseInt(Ext.getCmp('PohonTotal').getValue());
        if(totalNya > 0) {
            Ext.getCmp('PohonTotalPersen').setValue('100 %');
        }

        var rehabNya = parseInt(Ext.getCmp('PohonRehab').getValue());
        if(rehabNya > 0 && totalNya > 0){
            var persenNyaRehab = (rehabNya / totalNya) * 100;
            Ext.getCmp('PohonRehabPersen').setValue(persenNyaRehab.toFixed(2)+' %');
        }else{
            Ext.getCmp('PohonRehabPersen').setValue('0 %');
        }

        var tmNya = parseInt(Ext.getCmp('PohonTM').getValue());
        if(tmNya > 0 && totalNya > 0){
            var persenNyaTM = (tmNya / totalNya) * 100;
            Ext.getCmp('PohonTMPersen').setValue(persenNyaTM.toFixed(2)+' %');
        }else{
            Ext.getCmp('PohonTMPersen').setValue('0 %');
        }

        var tbmNya = parseInt(Ext.getCmp('PohonTBM').getValue());
        if(tbmNya > 0 && totalNya > 0){
            var persenNyaTBM = (tbmNya / totalNya) * 100;
            Ext.getCmp('PohonTBMPersen').setValue(persenNyaTBM.toFixed(2)+' %');
        }else{
            Ext.getCmp('PohonTBMPersen').setValue('0 %');
        }
    }
