    function CheckNotifPelindung() {
        if (Ext.getCmp('PruningProtectPlants').getValue() == '1') {
            if (parseFloat(Ext.getCmp('FrequentPruningProtect').getValue()) <= 0 || !isNumber(Ext.getCmp('FrequentPruningProtect').getValue())) Ext.getCmp('FrequentPruningProtect').addCls('notif-red');
            else Ext.getCmp('FrequentPruningProtect').removeCls('notif-red');
        } else {
            Ext.getCmp('FrequentPruningProtect').removeCls('notif-red');
        }
    }

    function CheckNotifPemangkasan() {
        if (Ext.getCmp('PruningPlants').getValue() == '1') {
            if (parseFloat(Ext.getCmp('FrequentPruning').getValue()) <= 0 || !isNumber(Ext.getCmp('FrequentPruning').getValue())) Ext.getCmp('FrequentPruning').addCls('notif-red');
            else Ext.getCmp('FrequentPruning').removeCls('notif-red');
            if (parseFloat(Ext.getCmp('HighPruning').getValue()) <= 0 || !isNumber(Ext.getCmp('HighPruning').getValue())) Ext.getCmp('HighPruning').addCls('notif-red');
            else Ext.getCmp('HighPruning').removeCls('notif-red');
        } else {
            Ext.getCmp('FrequentPruning').removeCls('notif-red');
            Ext.getCmp('HighPruning').removeCls('notif-red');
        }
    }

    function CheckNotifPohon() {
        if (parseFloat(Ext.getCmp('FrUrea').getValue()) > 0 || parseFloat(Ext.getCmp('FrDolomiteLime').getValue()) > 0 || parseFloat(Ext.getCmp('FrCocoaSpecific').getValue()) > 0 || parseFloat(Ext.getCmp('FrZa').getValue()) > 0 || parseFloat(Ext.getCmp('FrTsp').getValue()) > 0 || parseFloat(Ext.getCmp('FrNpk').getValue()) > 0 || parseFloat(Ext.getCmp('FrKcl').getValue()) > 0 || parseFloat(Ext.getCmp('FrLain').getValue()) > 0 || parseFloat(Ext.getCmp('FrFoliar').getValue()) > 0 || parseFloat(Ext.getCmp('FrFertiliaKakao').getValue()) > 0 || parseFloat(Ext.getCmp('FrNitrabor').getValue()) > 0) {
            if (Ext.getCmp('pTBM').getValue() == '1' || Ext.getCmp('pTM').getValue() == '1' || Ext.getCmp('pTR').getValue() == '1') {
                Ext.getCmp('pTBM').removeCls('notif-red');
                Ext.getCmp('pTM').removeCls('notif-red');
                Ext.getCmp('pTR').removeCls('notif-red');
            } else {
                Ext.getCmp('pTBM').addCls('notif-red');
                Ext.getCmp('pTM').addCls('notif-red');
                Ext.getCmp('pTR').addCls('notif-red');
            }
        }
    }

    function calcCompostYear(field, nv, ov) {
        var Fr = parseFloat(Ext.getCmp('FrequentFertilizationKompos').getValue());
        var Do = parseFloat(Ext.getCmp('DoseFertilizerKompos').getValue());
        var result = Fr * Do;
        if (result > 10) {
            Ext.Msg.alert('Warning', lang('Maksimal 10 kg/pohon/tahun'));
            field.setValue(ov);
        } else {
            Ext.getCmp('DoseFertilizerKomposYear').setValue(result);
        }
    }

    function calcManureYear(field, nv, ov) {
        var Fr = parseFloat(Ext.getCmp('FrKomposKandang').getValue());
        var Do = parseFloat(Ext.getCmp('DoKomposKandang').getValue());
        var result = Fr * Do;
        if (result > 10) {
            Ext.Msg.alert('Warning', lang('Maksimal 10 kg/pohon/tahun'));
            field.setValue(ov);
        } else {
            Ext.getCmp('DoKomposKandangYear').setValue(result);
        }
    }

    function calcLiquidYear() {
        var Fr = parseFloat(Ext.getCmp('FrKomposCair').getValue());
        var Do = parseFloat(Ext.getCmp('DoKomposCair').getValue());
        Ext.getCmp('DoKomposCairYear').setValue(Fr * Do);
    }

    function calcGranuleYear() {
        var Fr = parseFloat(Ext.getCmp('FrKomposGranula').getValue());
        var Do = parseFloat(Ext.getCmp('DoKomposGranula').getValue());
        Ext.getCmp('DoKomposGranulaYear').setValue(Fr * Do);
    }

    function calcPengapuran(){
        var Fr = parseFloat(Ext.getCmp('FrPengapuran').getValue());
        var Do = parseFloat(Ext.getCmp('DosePengapuran').getValue());
        Ext.getCmp('DosePengapuranYear').setValue(Fr * Do);
    }

    function CheckNotifPakaiKompos() {
        if (Ext.getCmp('PakaiKompos').getValue() == '1') {
            if (parseFloat(Ext.getCmp('DoseFertilizerKompos').getValue()) > 0) Ext.getCmp('DoseFertilizerKompos').removeCls('notif-red');
            else Ext.getCmp('DoseFertilizerKompos').addCls('notif-red');
            if (parseFloat(Ext.getCmp('FrequentFertilizationKompos').getValue()) > 0) Ext.getCmp('FrequentFertilizationKompos').removeCls('notif-red');
            else Ext.getCmp('FrequentFertilizationKompos').addCls('notif-red');
            //if (parseFloat(Ext.getCmp('TotalKompos').getValue())<=0) Ext.getCmp('TotalKompos').addCls('notif-red');
            //else Ext.getCmp('TotalKompos').removeCls('notif-red');
            CheckNotifTbm()
        } else {
            Ext.getCmp('DoseFertilizerKompos').removeCls('notif-red');
            Ext.getCmp('FrequentFertilizationKompos').removeCls('notif-red');
            //Ext.getCmp('TotalKompos').removeCls('notif-red');
            Ext.getCmp('kTBM').removeCls('notif-red');
            Ext.getCmp('kTM').removeCls('notif-red');
            Ext.getCmp('kTR').removeCls('notif-red');
        }
    }

    function CheckNotifTbm() {
        if (Ext.getCmp('kTBM').getValue() == '' && Ext.getCmp('kTM').getValue() == '' && Ext.getCmp('kTR').getValue() == '') {
            Ext.getCmp('kTBM').addCls('notif-red');
            Ext.getCmp('kTM').addCls('notif-red');
            Ext.getCmp('kTR').addCls('notif-red');
        } else {
            Ext.getCmp('kTBM').removeCls('notif-red');
            Ext.getCmp('kTM').removeCls('notif-red');
            Ext.getCmp('kTR').removeCls('notif-red');
        }
    }

