    function setGardenStatus(newValue) {
        if (newValue == 2) {
            Ext.getCmp('GardenStatus').setReadOnly(false);
            // Ext.getCmp('gardenstatus_remarks').setReadOnly(false);
            // Ext.getCmp('GardenStatus').allowBlank = false;
            Ext.apply(Ext.getCmp('GardenStatus'), {allowBlank: false}, {});
        } else {
            Ext.getCmp('GardenStatus').setValue('').setReadOnly(true);
            // Ext.getCmp('gardenstatus_remarks').setValue('');
            // Ext.getCmp('GardenStatus').allowBlank = true;
            Ext.apply(Ext.getCmp('GardenStatus'), {allowBlank: true}, {});
        }
        Ext.getCmp('GardenStatus').validate();
    }

    function getAge(dateString) {
        var today = new Date();
        var birthDate = new Date(dateString);
        var age = today.getFullYear() - birthDate.getFullYear();
        var m = today.getMonth() - birthDate.getMonth();
        if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
            age--;
        }
        return age;
    }

    function checkField(idnya) {
        if (Ext.getCmp(idnya).getValue() == '' || Ext.getCmp(idnya).getValue() == null || Ext.getCmp(idnya).getValue() == 'null' || Ext.getCmp(idnya).getValue() == undefined || Ext.getCmp(idnya).getValue() == 'undefined') {
            return false;
        } else {
            return true;
        }
    }

