    var currentTime = new Date();
    var now = currentTime.getFullYear();
    var years = [];
    var yearsb = [];
    var y = now;
    while (y > 1979) {
        years.push([y]);
        y--;
    }
    var y = now;
    while (y > 1989) {
        yearsb.push([y]);
        y--;
    }
    var storeThn = new Ext.data.SimpleStore({
        fields: ['tahun'],
        data: years
    });
    var storeThnb = new Ext.data.SimpleStore({
        fields: ['tahun'],
        data: yearsb
    });

    function hideSave() {
        Ext.getCmp('asaveButton').hide();
        if (Ext.getCmp('id').getValue() === '' && m_act_add) {
            Ext.getCmp('asaveButton').show();
        }
        if (Ext.getCmp('id').getValue() !== '' && m_act_update) {
            Ext.getCmp('asaveButton').show();
        }
    }

    function displayFormWindow() {
        Ext.getCmp('Desa').setValue();
        Ext.getCmp('iphoto').setSrc();
        Ext.getCmp('Provinsi').setValue(m_Province).setDisabled(false);
        Ext.getCmp('Kabupaten').setValue(m_District).setDisabled(false);
        if (!win.isVisible()) {
            DataForm.getForm().reset();
            //Ext.getCmp('data_umum').disable();
            //Ext.getCmp('data_umum_lanjutan').disable();
            //Ext.getCmp('data_umum_pelatihan').disable();
            //Ext.getCmp('keluarga').disable();
            win.center();
            win.show();
            Ext.Ajax.request({
                url: m_area,
                method: 'GET',
                params: {
                    key: m_param
                },
                success: function(fp, o) {
                    var r = Ext.decode(fp.responseText);
                    Ext.getCmp('Provinsi').setValue(r.Provinsi);
                }
            });
            Ext.getCmp('Kabupaten').setValue(m_District);
            mc_GroupID.load({
                params: {
                    prov: m_param,
                    kab: m_District
                }
            });
            Ext.getCmp('PersonNm').focus(true, true);
            Ext.getCmp('Kecamatan').setValue();
        } else {
            win.hide(this, function() {});
            win.toFront();
        }
        Ext.getCmp('win').center()
    }
