    function displayFormGarden() {
        if (!winGarden.isVisible()) {
            DataFormGarden.getForm().reset();
            winGarden.center();
            winGarden.show();
        } else {
            winGarden.hide(this, function() {});
            winGarden.center();
            winGarden.toFront();
        }
    }

    function checking() {
        if (Ext.getCmp('PruningPlants').getValue()) {
            Ext.getCmp('FrequentPruning').setDisabled(false);
            Ext.getCmp('HighPruning').setDisabled(false);
        } else {
            Ext.getCmp('FrequentPruning').setDisabled(true);
            Ext.getCmp('HighPruning').setDisabled(true);
        }
    }

