                                                            success: function(form, action) {
                                                                var r = Ext.decode(action.response.responseText);
                                                                Ext.getCmp('FormCertificationAudit').getForm().findField("InpectorID").setValue(r.data.InspectorID);
                                                                Ext.getCmp('FarmerIDFormCert').setValue(Ext.getCmp('gFarmerID').getValue());
                                                                Ext.getCmp('GardenNrFormCert').setValue(Ext.getCmp('GardenNr').getValue());
                                                                Ext.getCmp('SurveyNrFormCert').setValue(Ext.getCmp('gSurveyNr').getValue());
                                                                Ext.getCmp('CertificationFormEdit').setValue('1');
                                                                Ext.getCmp('CertificationFormCert').setValue(Ext.getCmp('Certification').getValue().Certification);
                                                            }
