            id: 'csaveButton',
            text: lang('Save'),
            margin: '5px',
            scale: 'large',
            ui: 's-button',
            cls: 's-blue ' + m_act_save,
            handler: function() {
                var gFarmerID = Ext.getCmp('gFarmerID').getValue()
                var GardenNr = Ext.getCmp('GardenNr').getValue()
                var SurveyNr = Ext.getCmp('gSurveyNr').getValue()
                if (SurveyNr == undefined || SurveyNr == '') {
                    Ext.MessageBox.alert('Warning', 'Silahkan pilih SurveyNr');
                    return
                }
                if (GardenNr != undefined && SurveyNr != undefined) {
                    var tanda = SurveyNr.split(' - ');
                    Ext.Ajax.request({
                        url: m_garden,
                        method: 'GET',
                        params: {
                            id: Ext.getCmp('gFarmerID').getValue(),
                            GardenNr: Ext.getCmp('GardenNr').getValue(),
                            gSurveyNr: tanda[0]
                        },
                        success: function(fp, o) {
                            var r = Ext.decode(fp.responseText);
                            if (r.success == false || Ext.getCmp('GardenNr').readOnly == true) {
                                var formc = Ext.getCmp('dataFormGarden').getForm();
                                if (formc.isValid()) {
                                    formc.submit({
                                        url: m_garden + '_all',
                                        method: 'POST',
                                        waitMsg: 'Sending data...',
                                        success: function(fp, o) {
                                            //displayAntara('Kebun');
                                            Ext.MessageBox.alert('Success', 'Data saved.');

                                            store.load();
                                            store_antara.load({
                                                params: {
                                                    farmer_id: FarmerID,
                                                    jenis: 'Kebun'
                                                }
                                            });
                                            winGarden.hide();

                                            if (Ext.getCmp('Certification').getValue().Certification != '' || Ext.getCmp('Certification').getValue().Certification != null) {
                                                Ext.getCmp('auditLogBtn').setDisabled(false);
                                            } else {
                                                Ext.getCmp('auditLogBtn').setDisabled(true);
                                            }
                                        }
                                    });
                                }else{
                                    Ext.MessageBox.show({
                                        title: 'Failed',
                                        msg: 'Please fill the required field',
                                        buttons: Ext.MessageBox.OK,
                                        animateTarget: 'mb9',
                                        icon: 'ext-mb-info'
                                    });
                                }
                            } else {
                                Ext.MessageBox.alert('Warning', 'Kebun ' + GardenNr + ' Survey ' + SurveyNr + ' sudah ada');
                            }
                        }
                    });
                }
            }
