                        Ext.getCmp('fgvalidation').setValue(r.isValid);
                        Ext.getCmp('fgcomment').setValue(r.CommentValid);
                        if (r.ApprovedByME == '1') Ext.getCmp('ApprovedByME').setValue(true);
                        if (r.ApprovedByGO == '1') Ext.getCmp('ApprovedByGO').setValue(true);
                        if (r.ApprovedByDC == '1') Ext.getCmp('ApprovedByDC').setValue(true);
