    function displayFormClonalGarden() {
        if (!winClonalGarden.isVisible()) {
            DataFormClonalGarden.getForm().reset();
            Ext.getCmp('FCGObjID').setValue(Ext.getCmp('FarmerID').getValue());
            winClonalGarden.center();
            winClonalGarden.show();
        } else {
            winClonalGarden.hide(this, function() {});
            winClonalGarden.center();
            winClonalGarden.toFront();
        }
    }
