    function displayAntara(jenis) {
        title = jenis
        if (jenis == 'AFF') title = 'Financial';
        winAntara.setTitle(lang(title))
        jenis = jenis;
        if (jenis != 'Kebun') columndata = [
        {
            text: lang('No'),
            xtype: 'rownumberer',
            align: 'center',
            width: '5%'
        },
        {
            text: lang('Survey'),
            dataIndex: 'survey',
            width: '75%'
        }, {
            text: lang('Date Collection'),
            dataIndex: 'date',
            width: '20%'
        }
        ];
        else columndata = [
        {
            text: lang('No'),
            xtype: 'rownumberer',
            align: 'center',
            width: '5%'
        },
        {
            text: lang('Garden'),
            dataIndex: 'garden',
            width: '35%'
        }, {
            text: lang('Survey'),
            dataIndex: 'survey',
            width: '40%'
        }, {
            text: lang('Date Collection'),
            dataIndex: 'date',
            width: '20%'
        }];
        //winAntar(jenis);
        DataAntar(columndata, jenis);
        store_antara.load({
            params: {
                farmer_id: FarmerID,
                jenis: jenis
            }
        });
        if (!winAntara.isVisible()) {
            winAntara.center();
            winAntara.show();
            winAntara.toFront();
        } else {
            winAntara.hide(this, function() {});
            winAntara.center();
            winAntara.toFront();
        }
    }
