            console.log('insert');
            Ext.getCmp('sinutriSurveyNr').setReadOnly(false);

            //get info petani
            Ext.Ajax.request({
                url: m_api + '/farmer/farmerl',
                method: 'GET',
                waitMsg: lang('Please Wait'),
                params: {
                    id: Ext.getCmp('FarmerID').getValue()
                },
                success: function(data) {
                    var jsonResp = JSON.parse(data.responseText);
                    //console.log(jsonResp);
                    Ext.getCmp('sinutriFarmerID').setValue(jsonResp.FarmerID);
                    Ext.getCmp('sinutriFarmerName').setValue(jsonResp.FarmerName);

                    //set form default
                    Ext.getCmp('sinutriHaveVegetableGarden2').setValue(true);
                    Ext.getCmp('sinutriHaveFishPond2').setValue(true);
                    Ext.getCmp('sinutriHaveChildren2').setValue(true);
                },
                failure: function(data) {
                    Ext.MessageBox.show({
                        title: 'Failed',
                        msg: 'Data not found',
                        buttons: Ext.MessageBox.OK,
                        animateTarget: 'mb9',
                        icon: 'ext-mb-error'
                    });
                }
            });
